class Solution(object):
    def isPathCrossing(self, path):
        visited = {(0, 0)}
        x, y = 0, 0
        directions = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
        for move in path:
            dx, dy = directions[move]
            x, y = x + dx, y + dy
            if (x, y) in visited:
                return True
            visited.add((x, y))
        return False
